+function asRoleContentMessage(message: SessionHistoryMessage): RoleContentMessage | null {
+  const role = typeof message.role === "string" ? message.role.toLowerCase() : "";
+  if (!role) {
+    return null;
+  }
+  return {
+    role,
+    ...(message.content !== undefined
